from flask import Flask, redirect, url_for, request, session
import requests
import json

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key_here'

# OpenID Connect configuration
oidc_provider_url = "https://your_oidc_provider.com"
client_id = "your_client_id_here"
redirect_uri = url_for('callback', _external=True)

@app.route('/')
def index():
    return redirect(url_for('login'))

@app.route('/login')
def login():
    authorization_url = f"{oidc_provider_url}/authorize?"
    authorization_url += f"client_id={client_id}&"
    authorization_url += f"redirect_uri={redirect_uri}&"
    authorization_url += "response_type=code&"
    authorization_url += "scope=openid profile email"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_url = f"{oidc_provider_url}/token?"
    token_url += f"grant_type=authorization_code&"
    token_url += f"client_id={client_id}&"
    token_url += f"redirect_uri={redirect_uri}&"
    token_url += "code=" + code
    headers = {'Content-Type': 'application/x-www-form-urlencoded'}
    response = requests.post(token_url, headers=headers)
    tokens = json.loads(response.text)
    id_token = tokens['id_token']
    # Validate nonce to prevent attacks (e.g., using a random value for nonce in the authorization request)
    if 'nonce' in session:
        del session['nonce']
    user_info_url = f"{oidc_provider_url}/userinfo?"
    user_info_url += "access_token=" + tokens['access_token']
    response = requests.get(user_info_url)
    user_info = json.loads(response.text)
    # Store user information in the session
    session['user'] = {
        'username': user_info['preferred_username'],
        'email': user_info['email'],
        'name': user_info['name']
    }
    return redirect(url_for('protected'))

@app.route('/protected')
def protected():
    if 'user' not in session:
        return redirect(url_for('login'))
    return "Hello, {}!".format(session['user']['username'])

if __name__ == '__main__':
    app.run(debug=True)